/**
 * Builds aggregation query based on parameters
 */
function buildAggregationQuery(dataset, table, aggregationType, dateRange, groupByColumns) {
  const fullyQualifiedTable = `\`${dataset}.${table}\``;

  let whereClause = '';
  if (dateRange.startDate && dateRange.endDate) {
    whereClause = `WHERE created_at BETWEEN '${dateRange.startDate}' AND '${dateRange.endDate}'`;
  } else if (dateRange.startDate) {
    whereClause = `WHERE created_at >= '${dateRange.startDate}'`;
  }

  const groupByClause = groupByColumns.length > 0
    ? `GROUP BY ${groupByColumns.join(', ')}`
    : '';

  const groupBySelect = groupByColumns.length > 0
    ? `${groupByColumns.join(', ')},`
    : '';

  switch (aggregationType) {
    case 'count':
      return `
        SELECT 
          ${groupBySelect}
          COUNT(*) as total_count,
          COUNT(DISTINCT id) as unique_count
        FROM ${fullyQualifiedTable}
        ${whereClause}
        ${groupByClause}
      `;

    case 'statistical':
      return `
        SELECT 
          ${groupBySelect}
          COUNT(*) as total_count,
          AVG(value) as avg_value,
          STDDEV(value) as stddev_value,
          MIN(value) as min_value,
          MAX(value) as max_value,
          APPROX_QUANTILES(value, 100)[OFFSET(25)] as p25,
          APPROX_QUANTILES(value, 100)[OFFSET(50)] as median,
          APPROX_QUANTILES(value, 100)[OFFSET(75)] as p75,
          APPROX_QUANTILES(value, 100)[OFFSET(95)] as p95,
          APPROX_QUANTILES(value, 100)[OFFSET(99)] as p99
        FROM ${fullyQualifiedTable}
        ${whereClause}
        ${groupByClause}
      `;

    case 'timeseries':
      return `
        SELECT 
          DATE_TRUNC(created_at, DAY) as date_bucket,
          ${groupBySelect}
          COUNT(*) as count,
          SUM(value) as total_value,
          AVG(value) as avg_value,
          MIN(value) as min_value,
          MAX(value) as max_value
        FROM ${fullyQualifiedTable}
        ${whereClause}
        GROUP BY date_bucket${groupByColumns.length > 0 ? ', ' + groupByColumns.join(', ') : ''}
        ORDER BY date_bucket ASC
      `;

    case 'full':
    default:
      return `
        SELECT *
        FROM ${fullyQualifiedTable}
        ${whereClause}
        ORDER BY created_at DESC
      `;
  }
}

/**
 * Process large result sets in chunks to manage memory
 */
async function processInChunks(rows, chunkSize) {
  const processedData = [];
  const totalChunks = Math.ceil(rows.length / chunkSize);

  console.log(`Processing ${rows.length} rows in ${totalChunks} chunks of ${chunkSize}`);

  for (let i = 0; i < rows.length; i += chunkSize) {
    const chunkIndex = Math.floor(i / chunkSize) + 1;
    const chunk = rows.slice(i, i + chunkSize);

    console.log(`Processing chunk ${chunkIndex}/${totalChunks} (${chunk.length} rows)`);

    // Process each chunk - transform, clean, and aggregate
    const processedChunk = chunk.map(row => {
      const processed = { ...row };

      // Convert BigQuery numeric types
      for (const key of Object.keys(processed)) {
        if (processed[key] && typeof processed[key] === 'object' && processed[key].value !== undefined) {
          processed[key] = Number(processed[key].value);
        }
      }

      return processed;
    });

    processedData.push(...processedChunk);

    // Force garbage collection hint between chunks
    if (global.gc) {
      global.gc();
    }

    // Log memory usage periodically
    if (chunkIndex % 10 === 0) {
      console.log(`Memory after chunk ${chunkIndex}: ${formatMemoryUsage()}`);
    }
  }

  return processedData;
}

